框架​ ​序列化​速度​ ​体积​ ​可读性​ ​跨​语言​ ​适用​场景​ JSON (Jackson) ​中​ ​大​ ​高​ ​是​ REST API、​配置文件​ Protobuf ​快​ ​小​ ​低​ ​是​ gRPC、​高性能​通信​ Kryo ​最快​ ​最小​ ​低​ ​否​ Java ​内部​通信​、​缓存​ MessagePack ​快​ ​较​小​ ​低​ ​是​ ​跨​语言​高性能​场景​ Hessian ​中​ ​中​ ​低​ ​是​ Dubbo ​默认​序列化​ <pre><code>// Jackson ​性能​优化​配置​
@Configuration
public class JacksonOptimizationConfig {

    @Bean
    public ObjectMapper optimizedObjectMapper() {
        ObjectMapper mapper = new ObjectMapper();

        // ​性能​优化​配置​
        mapper.configure(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES, false);
        mapper.configure(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS, false);
        mapper.setSerializationInclusion(JsonInclude.Include.NON_NULL); // ​不​序列化​ null

        // ​使用​ AfterBurner ​模块​加速​（​基于​字节码​生成​）
        mapper.registerModule(new AfterburnerModule());

        // ​日期​格式​
        mapper.registerModule(new JavaTimeModule());

        return mapper;
    }
}

